'use strict';

const { seedDefaultUsers } = require('./client-auth');

const SEED_VERSION = 3;

function toRow(o) {
  return [
    o.id, o.clientId, o.clientName, o.channel, o.orderDate || o.orderedAt,
    o.status, o.currency || 'SGD', o.notes || '',
    JSON.stringify(o.items    || []),
    JSON.stringify(o.shipping || {}),
    o.subtotal || 0, o.shippingCost || 0, o.tax || 0, o.total || 0,
    JSON.stringify(o.source   || {}),
  ];
}

function fromRow(r) {
  return {
    id:           r.id,
    clientId:     r.client_id,
    clientName:   r.client_name,
    channel:      r.channel,
    orderDate:    r.order_date,
    status:       r.status,
    currency:     r.currency,
    notes:        r.notes,
    items:        JSON.parse(r.items    || '[]'),
    shipping:     JSON.parse(r.shipping || '{}'),
    subtotal:     r.subtotal,
    shippingCost: r.shipping_cost,
    tax:          r.tax,
    total:        r.total,
    source:       JSON.parse(r.source   || '{}'),
  };
}

