// ── Factory ───────────────────────────────────────────────────────────────────

module.exports = function createStore(db) {
  const INSERT = db.prepare(`
    INSERT OR IGNORE INTO orders
      (id, client_id, client_name, channel, order_date, status, currency, notes,
       items, shipping, subtotal, shipping_cost, tax, total, source)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);

  // Reseed when SEED_VERSION bumps so dashboard always shows the demo data
  const { n } = db.prepare('SELECT COUNT(*) AS n FROM orders').get();
  const seedRow = db.prepare("SELECT value FROM settings WHERE key='seed_version'").get();
  const currentSeedVer = seedRow ? parseInt(seedRow.value) : 0;
  if (n === 0 || currentSeedVer < SEED_VERSION) {
    db.prepare('DELETE FROM orders').run();
    db.transaction(seeds => seeds.forEach(o => INSERT.run(...toRow(o))))(SEED);
    db.prepare("INSERT OR REPLACE INTO settings (key, value) VALUES ('seed_version', ?)").run(String(SEED_VERSION));
    seedDefaultUsers(db);
  }

  function getOrders({ clientId, channel, status, search } = {}) {
    let sql = 'SELECT * FROM orders WHERE 1=1';
    const params = [];
    if (clientId) { sql += ' AND client_id = ?';  params.push(clientId); }
    if (channel)  { sql += ' AND channel = ?';     params.push(channel); }
    if (status)   { sql += ' AND status = ?';      params.push(status); }
    sql += ' ORDER BY order_date DESC';
    let rows = db.prepare(sql).all(...params).map(fromRow);
    if (search) {
      const q = search.toLowerCase();
      rows = rows.filter(o =>
        o.id.toLowerCase().includes(q) ||
        o.clientName.toLowerCase().includes(q) ||
        o.shipping.recipient.toLowerCase().includes(q)
      );
    }
    return rows;
  }

  function getOrder(id) {
    const row = db.prepare('SELECT * FROM orders WHERE id = ?').get(id);
    return row ? fromRow(row) : null;
  }

  function addOrder(order) {
    const exists = db.prepare('SELECT id FROM orders WHERE id = ?').get(order.id);
    if (exists) throw new Error(`Order ${order.id} already exists`);
    INSERT.run(...toRow(order));
    return order;
  }

  function getStats() {
    const rows     = db.prepare('SELECT status, channel, client_id, client_name, total FROM orders').all();
    const byStatus = {}, byChannel = {}, byClientMap = {};
    for (const o of rows) {
      byStatus[o.status] = (byStatus[o.status] || 0) + 1;
      if (!byChannel[o.channel]) byChannel[o.channel] = { count: 0, revenue: 0 };
      byChannel[o.channel].count++;
      byChannel[o.channel].revenue = Math.round((byChannel[o.channel].revenue + o.total) * 100) / 100;
      if (!byClientMap[o.client_id]) byClientMap[o.client_id] = { clientId: o.client_id, clientName: o.client_name, count: 0, revenue: 0 };
      byClientMap[o.client_id].count++;
      byClientMap[o.client_id].revenue = Math.round((byClientMap[o.client_id].revenue + o.total) * 100) / 100;
    }
    return {
      totalOrders:   rows.length,
      totalRevenue:  Math.round(rows.reduce((s, o) => s + o.total, 0) * 100) / 100,
      totalClients:  Object.keys(byClientMap).length,
      totalChannels: Object.keys(byChannel).length,
      byStatus,
      byChannel,
      byClient: Object.values(byClientMap),
    };
  }

  function getClients() {
    return db.prepare(`
      SELECT client_id AS id, client_name AS name, COUNT(*) AS orderCount
      FROM orders GROUP BY client_id ORDER BY orderCount DESC
    `).all();
  }

  function getChannels() {
    return db.prepare(`
      SELECT channel, COUNT(*) AS count FROM orders GROUP BY channel ORDER BY count DESC
    `).all();
  }

  function deleteOrder(id) {
    const row = db.prepare('SELECT id FROM orders WHERE id = ?').get(id);
    if (!row) throw new Error(`Order ${id} not found`);
    db.prepare('DELETE FROM orders WHERE id = ?').run(id);
  }

  function deleteAllOrders() {
    const { n } = db.prepare('SELECT COUNT(*) AS n FROM orders').get();
    db.prepare('DELETE FROM orders').run();
    return n;
  }

  function updateOrder(id, changes = {}) {
    const row = db.prepare('SELECT * FROM orders WHERE id = ?').get(id);
    if (!row) throw new Error(`Order ${id} not found`);
    const current = fromRow(row);

    const status   = changes.status   !== undefined ? changes.status   : current.status;
    const notes    = changes.notes    !== undefined ? changes.notes    : current.notes;
    const source   = changes.source   !== undefined ? { ...current.source,   ...changes.source }   : current.source;
    const shipping = changes.shipping !== undefined ? { ...current.shipping, ...changes.shipping } : current.shipping;

    db.prepare(`UPDATE orders SET status=?, notes=?, source=?, shipping=? WHERE id=?`)
      .run(status, notes, JSON.stringify(source), JSON.stringify(shipping), id);

    return getOrder(id);
  }

  function lookupByCode(code) {
    const q = code.trim();
    let row = db.prepare('SELECT * FROM orders WHERE id = ?').get(q);
    if (row) return fromRow(row);
    row = db.prepare('SELECT * FROM orders WHERE LOWER(id) = LOWER(?)').get(q);
    if (row) return fromRow(row);
    const all = db.prepare('SELECT * FROM orders').all();
    const ql = q.toLowerCase();
    for (const r of all) {
      const src = JSON.parse(r.source || '{}');
      if (src.trackingNo && src.trackingNo.toLowerCase() === ql) return fromRow(r);
    }
    const partial = all.find(r => r.id.toLowerCase().includes(ql));
    return partial ? fromRow(partial) : null;
  }

  function updateSource(id, fragment) {
    const row = db.prepare('SELECT source FROM orders WHERE id = ?').get(id);
    if (!row) return null;
    const merged = { ...JSON.parse(row.source || '{}'), ...fragment };
    db.prepare('UPDATE orders SET source = ? WHERE id = ?').run(JSON.stringify(merged), id);
    return getOrder(id);
  }

  function updateStatusAndSource(id, status, fragment) {
    return db.transaction(() => {
      const row = db.prepare('SELECT status, source FROM orders WHERE id = ?').get(id);
      if (!row) return null;
      const merged = { ...JSON.parse(row.source || '{}'), ...fragment };
      db.prepare('UPDATE orders SET status = ?, source = ? WHERE id = ?').run(status, JSON.stringify(merged), id);
      return getOrder(id);
    })();
  }

  return { getOrders, getOrder, addOrder, updateOrder, deleteOrder, deleteAllOrders, getStats, getClients, getChannels, lookupByCode, updateSource, updateStatusAndSource };
};
